import{_ as t,o,c as n,ag as a}from"./chunks/framework.ePeAWSvT.js";const r="/assets/datahub-endpoint-filters-tab.D-NqDnwO.png",s="/assets/datahub-endpoint-scheduler-tab.BfX5y7Ol.png",i="/assets/datahub-endpoint-variables-tab.B0ydQqzD.png",m=JSON.parse('{"title":"Scheduling & Automation","description":"","frontmatter":{},"headers":[],"relativePath":"guide/datahub-scheduling.md","filePath":"guide/datahub-scheduling.md"}'),l={name:"guide/datahub-scheduling.md"};function d(h,e,c,p,g,u){return o(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="scheduling-automation" tabindex="-1">Scheduling &amp; Automation <a class="header-anchor" href="#scheduling-automation" aria-label="Permalink to &quot;Scheduling &amp; Automation&quot;">​</a></h1><h2 id="publish-subscribe-filters" tabindex="-1">Publish/Subscribe Filters <a class="header-anchor" href="#publish-subscribe-filters" aria-label="Permalink to &quot;Publish/Subscribe Filters&quot;">​</a></h2><p>A Publish or Subscribe Filter enables you to create rules to build complex scenarios to determine <em>what</em> data gets published. You can create individual filters, as well as groups of filters; and then configure And/Or conditions at both the Group- and Item-level, as well as across groups and items.</p><p>For Publish Endpoints, some connectors like Salesforce, Microsoft, and NetSuite have powerful query capabilities inside of the API to perform complex filter logic at the API level; other Connectors do not have this capability. A Publishing Filter can be used to filter the payload that has been downloaded by a Connector, manipulating <em>what</em> data is published.</p><p>For Subscriber Endpoints, it allows an Endpoint to receive a message, but not process it based on the data that is received on the message.</p><ul><li><strong>Publishing Filter:</strong> Uses JSONPath or XPath to select a field from the Connector to use a comparison in the filter. (This is the same syntax as on an XML Simple Element Read mapping.)</li><li><strong>Subscriber Filter:</strong> Uses JSONPath to select a field from your Schema to use as a comparison in the filter. For example, to filter on a customer data value, use a JSONPath such as <code>CustomData[?(@.Name == &#39;Subscription3TimesRenewed&#39;)].Value</code>.</li></ul><div class="info custom-block"><p class="custom-block-title">NOTE</p><p>For additional help executing this functionality, contact TeamCentral Support.</p></div><div class="tip custom-block"><p class="custom-block-title">Map Group Filters</p><p>In addition to Publish/Subscribe Filters (which apply at the endpoint level), you can also configure filters directly on individual <strong>Map Groups</strong> within your action mappings. Map Group filters control which items are processed during mapping — for example, skipping certain line items on a save. See <a href="./datahub-action-mapping.html#map-group-filters">Map Group Filters</a> for details.</p></div><h3 id="configure-filters" tabindex="-1">Configure Filters <a class="header-anchor" href="#configure-filters" aria-label="Permalink to &quot;Configure Filters&quot;">​</a></h3><p><img src="'+r+'" alt="Endpoint Filters Tab"></p><ol><li><p>Select <strong>Build</strong> &gt; <strong>Data Hubs</strong> from the main menu.</p></li><li><p>Select the appropriate <strong>Data Hub</strong>; then, select the appropriate parent <strong>Endpoint</strong>.</p></li><li><p>Select the <strong>Filters</strong> tab.</p></li><li><p>As needed, select the <strong>arrow</strong> to expand the <strong>Publishing Filters</strong> or <strong>Subscriber Filters</strong> section.</p></li><li><p>Then, use the below table to determine next steps:</p></li></ol><div class="info custom-block"><p class="custom-block-title">NOTES</p><ul><li>If no filters have been previously defined, select the <strong>Add One</strong> button in the center of that section.</li><li>The Group name will be set as <strong>PublishingFilter</strong> or <strong>SubscriberFilter</strong> and cannot be edited.</li><li>When creating a new Filter, you will need to first <em>Create a New Filter Group</em>; then, <em>Add a New Item</em> to that filter group.</li></ul></div><table tabindex="0"><thead><tr><th>To:</th><th>Do this:</th></tr></thead><tbody><tr><td><strong>Create a New Filter Group</strong></td><td>Select <strong>+ Add Group</strong>. Select an option for <strong>Group And/Or</strong>, <strong>Item And/Or</strong>, and <strong>Subscriber Process Stage</strong> (<em>subscriber filters only</em>). Then, select <strong>Save</strong>.</td></tr><tr><td><strong>Add a New Item</strong></td><td>Select the <strong>+</strong> icon in the grey header row of that Filter Group. Enter or select data for the presented <strong>fields</strong> (the fields will vary based on your initial selections). Then, select <strong>Save</strong>. Repeat this process to add as many Items to that filter Group as needed.</td></tr><tr><td><strong>Edit a Filter Group</strong></td><td>Select the <strong>edit</strong> icon in the grey header row of that Filter Group. Edit the necessary fields and select <strong>Save</strong>.</td></tr><tr><td><strong>Edit an Item</strong></td><td>Select the <strong>edit</strong> icon in the appropriate item row. Edit the necessary fields and select <strong>Save</strong>.</td></tr><tr><td><strong>Delete a Filter Group</strong></td><td>Select the <strong>delete</strong> icon in the grey header row of that Filter Group. Select <strong>OK</strong> to confirm.</td></tr><tr><td><strong>Delete an Item</strong></td><td>Select the <strong>delete</strong> icon in the appropriate item row. Select <strong>OK</strong> to confirm.</td></tr></tbody></table><h2 id="scheduler" tabindex="-1">Scheduler <a class="header-anchor" href="#scheduler" aria-label="Permalink to &quot;Scheduler&quot;">​</a></h2><p>A Scheduler is available as a Publisher option only, and can be applied to schedule when data gets published.</p><p>There are several ways to schedule the data to be published:</p><ul><li><i class="fa-solid fa-play-pause text-secondary"></i> <strong>On Demand</strong> — Runs manually when the user decides to run.</li><li><i class="fa-solid fa-clock text-secondary"></i> <strong>Interval</strong> — Runs on a specific frequency based on Minutes and Seconds.</li><li><i class="fa-solid fa-calendar text-secondary"></i> <strong>Day of the Week</strong> — Runs on specific days of the week based on Time Zone, Days of the Week selected, Time (Hours and Minutes).</li><li><i class="fa-solid fa-calendar text-secondary"></i> <strong>Day of the Month</strong> — Runs on specific days of the month based on Time Zone, Days of the Month, Time (Hours and Minutes), Run Conditions (Any Day, Week Day Only Advance, Week Day Only Skip, Week Day Only).</li></ul><div class="tip custom-block"><p class="custom-block-title">Best Practice</p><p>When a Scheduler has been applied to an Endpoint, the corresponding scheduler icon (shown above) will appear on the Endpoint card within the Data Hub. Users can select to manually publish the Endpoint as needed, but it is advised to allow the scheduler to run as prescribed. This will help to avoid any duplicates and/or errors.</p></div><h3 id="configure-a-scheduler" tabindex="-1">Configure a Scheduler <a class="header-anchor" href="#configure-a-scheduler" aria-label="Permalink to &quot;Configure a Scheduler&quot;">​</a></h3><p><img src="'+s+'" alt="Endpoint Scheduler Tab"></p><ol><li><p>Select <strong>Build</strong> &gt; <strong>Data Hubs</strong> from the main menu.</p></li><li><p>Select the appropriate <strong>Data Hub</strong>; then, select the appropriate parent <strong>Endpoint</strong>.</p></li><li><p>Select the <strong>Scheduler</strong> tab.</p></li><li><p>Then, use the below table to determine next steps:</p></li></ol><table tabindex="0"><thead><tr><th>To:</th><th>Do this:</th></tr></thead><tbody><tr><td><strong>Create an On-Demand Schedule</strong></td><td>No additional set-up is required for On-Demand scheduling.</td></tr><tr><td><strong>Create an Interval Schedule</strong></td><td>Select the <strong>Scheduler Type: Interval</strong>. Enter the <strong>Minute</strong> and <strong>Second</strong> times. Then, select <strong>Save</strong>.</td></tr><tr><td><strong>Create a Day of the Week Schedule</strong></td><td>Select the <strong>Scheduler Type: Day of the Week</strong>. Select a <strong>Time Zone</strong>. Select <strong>Add Time</strong>. In the pop-up window, select the appropriate <strong>day(s)</strong> and enter a <strong>Time</strong>; then, select <strong>Save</strong>. The schedule will appear in the scheduler table. Repeat this process to create as many schedules as needed. When finished, select <strong>Save</strong> below the scheduler table to save all of the created schedules.</td></tr><tr><td><strong>Create a Day of the Month Schedule</strong></td><td>Select the <strong>Scheduler Type: Day of the Month</strong>. Select a <strong>Time Zone</strong>. Select <strong>Add Time</strong>. In the pop-up window, select the appropriate <strong>date(s)</strong>, enter a <strong>Time</strong>, and select a <strong>Run Condition</strong>; then, select <strong>Save</strong>. The schedule will appear in the scheduler table. Repeat this process to create as many schedules as needed. When finished, select <strong>Save</strong> below the scheduler table to save all of the created schedules.</td></tr><tr><td><strong>Edit an Interval Schedule</strong></td><td>Repeat the <em>Create an Interval Schedule</em> steps.</td></tr><tr><td><strong>Edit a Day of the Week/Month Schedule</strong></td><td>Select the appropriate <strong>Scheduler Type: Day of the Week/Month</strong>. Select the <strong>edit</strong> icon in the appropriate row. Edit the <strong>Schedule</strong> as needed; then, select <strong>Save</strong>.</td></tr><tr><td><strong>Delete a Day of the Week/Month Schedule</strong></td><td>Select the <strong>delete</strong> icon in the appropriate row. Select <strong>OK</strong> to confirm.</td></tr></tbody></table><h2 id="run-on-demand" tabindex="-1">Run On-Demand <a class="header-anchor" href="#run-on-demand" aria-label="Permalink to &quot;Run On-Demand&quot;">​</a></h2><p>When a publisher is set to On Demand, the endpoint can be executed by either clicking the <i class="fa-solid fa-play-pause text-secondary"></i> icon on the endpoint card, or clicking the ellipsis and selecting <strong>Run Publish</strong>.</p><p>This will bring up a dialog box that allows the user to select the date and time they would like the publisher to run from, along with a couple of toggle options described below.</p><h3 id="on-demand-options" tabindex="-1">On-Demand Options <a class="header-anchor" href="#on-demand-options" aria-label="Permalink to &quot;On-Demand Options&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Option</th><th>Description</th></tr></thead><tbody><tr><td><strong>Bi-directional Blocking</strong></td><td>Blocking checks are background actions that may prevent a record from being run back-to-back or too often. If <strong>Skip Blocking</strong> is turned ON, the system will ignore any blocking checks within the system. Toggle <strong>Skip Blocking</strong> ON or OFF as needed.</td></tr><tr><td><strong>Customize Request</strong></td><td>This is a one-time audit of the configured Endpoint. In this screen, you can modify the requests (e.g. change the route, designate a filter, etc.) and then run the modified configuration. When finished, the system will reset to the default settings once you close this window. Toggle <strong>Customize Request</strong> ON or OFF as needed.</td></tr></tbody></table><h2 id="variables" tabindex="-1">Variables <a class="header-anchor" href="#variables" aria-label="Permalink to &quot;Variables&quot;">​</a></h2><p>Variables enable you to create values that can be passed into the action and used as parameters for a URL or message body. For custom Endpoints, variables can be used as constants that can be referenced in code as an application setting.</p><div class="info custom-block"><p class="custom-block-title">NOTE</p><p>For additional help executing this functionality, contact TeamCentral Support.</p></div><h3 id="configure-variables" tabindex="-1">Configure Variables <a class="header-anchor" href="#configure-variables" aria-label="Permalink to &quot;Configure Variables&quot;">​</a></h3><p><img src="'+i+'" alt="Endpoint Variables Tab"></p><ol><li><p>Select <strong>Build</strong> &gt; <strong>Data Hubs</strong> from the main menu.</p></li><li><p>Select the appropriate <strong>Data Hub</strong>; then, select the appropriate parent <strong>Endpoint</strong>.</p></li><li><p>Select the <strong>Variables</strong> tab.</p></li><li><p>Then, use the below table to determine next steps:</p></li></ol><table tabindex="0"><thead><tr><th>To:</th><th>Do this:</th></tr></thead><tbody><tr><td><strong>Create a New Variable</strong></td><td>Select <strong>+ Add</strong>. Enter a <strong>Name</strong> and <strong>Value</strong>; then, select a <strong>Value Type</strong>. As needed, toggle <strong>Use Generated Value</strong> ON; then, enter or select <strong>data</strong> for those fields, which will vary based on your selections. Then, select <strong>Save</strong>.</td></tr><tr><td><strong>Edit a Variable</strong></td><td>Select the <strong>edit</strong> icon in the appropriate row. Edit the necessary fields; then, select <strong>Save</strong>.</td></tr><tr><td><strong>Delete a Variable</strong></td><td>Select the <strong>delete</strong> icon in the appropriate row. Select <strong>OK</strong> to confirm.</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Variables can be referenced in endpoint action URLs and bodies using parameterized syntax. See <a href="./datahub-endpoint-config.html#parameterizing">Endpoint Configuration</a> for details on the <code>{VAR:Name}</code> syntax.</p></div><h2 id="drop-down-lookups" tabindex="-1">Drop-Down Lookups <a class="header-anchor" href="#drop-down-lookups" aria-label="Permalink to &quot;Drop-Down Lookups&quot;">​</a></h2><p>Drop-down Lookups are a specific type of cross-reference within Central, and are confined to a single Data Hub. They are typically associated with Foreign Keys that do not fit into a particular entity type on the Common Model, so they are classified as General System Lookups.</p><p>When a key is received by the mapping engine for a particular value, it goes to the list of Drop-Down values that match the value for that system. Then, it uses the name of the Drop-Down value to pull in all other Drop-Down values that match that name.</p><div class="tip custom-block"><p class="custom-block-title">Example</p><p>You have an office location in Northwest Illinois. In Salesforce, that data might be written as NW-IL; however, in HubSpot, it may be written as a random string, 779f26-ghn11-ec145. You can build a Drop-Down Lookup to manage the cross-reference of this data.</p></div><p>A few important callouts on Drop-Down Lookups:</p><ul><li>The name of the Drop-Down field must match the name of the Foreign Key on your Schema.</li><li>Drop-Downs are scoped (limited) to a specific Data Hub.</li><li>An item inside of a Drop-Down list includes the name of the system, the name of the drop-down, and the value of the drop-down.</li><li>The mapping engine uses the name and the system values of each Drop-Down item for the cross-reference.</li></ul><h3 id="configure-drop-down-lookups" tabindex="-1">Configure Drop-Down Lookups <a class="header-anchor" href="#configure-drop-down-lookups" aria-label="Permalink to &quot;Configure Drop-Down Lookups&quot;">​</a></h3><ol><li><p>Select <strong>Build</strong> &gt; <strong>Data Hubs</strong> from the main menu.</p></li><li><p>Select the appropriate <strong>Data Hub</strong>; then select <strong>Actions</strong> &gt; <strong>Manage Drop Downs</strong>.</p><div class="info custom-block"><p class="custom-block-title">NOTE</p><p>You can select <strong>Actions</strong> &gt; <strong>Manage Drop Downs</strong> from within an Endpoint as well.</p></div></li><li><p>Then, use the below table to determine next steps:</p></li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><ul><li>When initially creating Drop-Down Lookups, you will need to <em>Create a New Drop-Down Field</em>; then, <em>Add A New Value</em>.</li><li>Additionally, after each step (creating the field, adding values, etc.), <strong>you must select Save</strong> at the top of the screen.</li></ul></div><table tabindex="0"><thead><tr><th>To:</th><th>Do this:</th></tr></thead><tbody><tr><td><strong>Create a New Drop-Down Field</strong></td><td>Select an <strong>Entity Type</strong>. Select <strong>Add One</strong>. Enter a <strong>Field Name</strong>. Select <strong>Save</strong>.</td></tr><tr><td><strong>Add a New Value</strong></td><td>Select the appropriate <strong>Entity Type</strong> and <strong>Drop Downs Field</strong>. Enter appropriate text in the <strong>Name</strong> field. Select the appropriate <strong>System</strong> from the drop-down list. Enter appropriate text in the <strong>Value</strong> field. Select <strong>+ Add</strong>. Repeat this process to add as many values as needed. Select <strong>Save</strong>.</td></tr><tr><td><strong>Designate a Default Value</strong></td><td>Select the appropriate <strong>Entity Type</strong> and <strong>Drop Downs Field</strong>. Select the <strong>Is Default</strong> checkbox for the appropriate Value. Select <strong>Save</strong>.</td></tr><tr><td><strong>Edit a Drop-Down Field Name</strong></td><td>Select the appropriate <strong>Entity Type</strong> and <strong>Drop Downs Field</strong>. Edit the <strong>Field Name</strong>; then, select <strong>Save</strong>.</td></tr><tr><td><strong>Delete a Drop-Down Field</strong></td><td>Select the appropriate <strong>Entity Type</strong> and <strong>Drop Downs Field</strong>. Select <strong>Delete</strong>. Select <strong>Yes</strong> to confirm.</td></tr><tr><td><strong>Delete a Value</strong></td><td>Select the appropriate <strong>Entity Type</strong> and <strong>Drop Downs Field</strong>. Select the <strong>delete</strong> icon in the appropriate row. Note: You will not be prompted to confirm the deletion of a Value.</td></tr></tbody></table><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./datahub-endpoint-settings.html">Endpoint Settings</a> — Configure processing behavior and supported operations</li><li><a href="./datahub-endpoint-config.html">Endpoint Configuration</a> — Configure endpoint action inputs and parameterization</li><li><a href="./datahub-data-adaptation.html">Data Adaptation</a> — Transform data as it flows between systems</li><li><a href="./build-datahubs.html">Building Data Hubs</a> — Create Data Hubs and add endpoints</li></ul>',47)])])}const f=t(l,[["render",d]]);export{m as __pageData,f as default};
